import jwt
import datetime
import hashlib
import secrets

SECRET_KEY = secrets.token_hex(32)
ALGORITHM = "HS256"

def generate_jwt(user_id, role):
    payload = {
        'exp': datetime.datetime.utcnow() + datetime.timedelta(minutes=30),
        'iat': datetime.datetime.utcnow(),
        'sub': user_id,
        'role': role
    }

    token = jwt.encode(
        payload,
        SECRET_KEY,
        algorithm=ALGORITHM
    )

    return token